.merge-tags ul li ul li {
    cursor: pointer;
}
.group-title {
  background-color: #4b4c4d;
  color: #fff;
  display: block;
  padding: 5px 10px
}
.el-dropdown-menu {
  left: unset;
  max-width: 270px;
}
.el-dropdown-list {
  border: 0;
  box-shadow: none;
  margin: 0;
  max-height: 280px;
  min-width: auto;
  overflow-y: scroll;
  padding: 0;
  position: static;
  z-index: 10
}
.el-dropdown-list .el-dropdown-menu__item {
  border-bottom: 1px solid #f1f1f1;
  font-size: 13px;
  line-height: 18px;
  padding: 4px 10px
}
.el-dropdown-list .el-dropdown-menu__item:last-of-type {
  border-bottom: 0
}
.el-popper[x-placement^=bottom] .popper__arrow {
  top: -7px
}



